mapper.select:
SELECT table_name FROM device_group WHERE `status` = 1 AND is_delete = 0 AND id IN (
#{item.id_device_group}
)

mapper.update:
UPDATE
	employee_chart_filter
SET
	name = #{name}
WHERE
	id = #{id}

mapper.delete:
  		WITH cte AS (
			SELECT
				id,
				ROW_NUMBER() OVER (ORDER BY id DESC) AS row_num
			FROM
				employee_chart_filter
			WHERE
				id_employee = #{id_employee}
				AND SHA1(id_site) = #{hash_id_site}
				AND is_favorite = #{is_favorite}
		)

  		DELETE FROM employee_chart_filter
	 	WHERE
	 		id_employee = #{id_employee}
	 		AND SHA1(id_site) = #{hash_id_site}
	 		AND is_favorite = #{is_favorite}
	 		AND id IN (SELECT id FROM cte WHERE row_num > 10)

mapper.select:
SELECT DATE_FORMAT(CONVERT_TZ(time, 'UTC', t.value), '%H:00') AS categories_time, DATE_FORMAT(CONVERT_TZ(time, 'UTC', t.value), '%Y-%m-%d %H:00') AS time_full,
AS actual FROM ${datatablename} dv JOIN device d ON d.id = dv.id_device JOIN site s ON s.id = d.id_site JOIN time_zone t ON t.id = s.id_time_zone JOIN ( SELECT
AS leadTimeValid, MIN(dv.time) AS minTime, MAX(dv.time) AS maxTime FROM ${datatablename} dv JOIN device d ON d.id = dv.id_device JOIN site s ON s.id = d.id_site JOIN time_zone t ON t.id = s.id_time_zone WHERE dv.id_device = #{id} AND time BETWEEN CONVERT_TZ(#{start_date}, t.value, 'UTC') AND CONVERT_TZ(#{end_date}, t.value, 'UTC') GROUP BY
) m ON m.minTime = dv.time AND dv.id_device = #{id}
